})(); // fim BLOCO 3


// ══════════════════════════════════════════════════════════════════════════════
//
//  ██████╗ ██╗      ██████╗  ██████╗  ██████╗     ██╗  ██╗
//  ██╔══██╗██║     ██╔═══██╗██╔════╝ ██╔═══██╗    ██║  ██║
